#!/usr/bin/env python3
"""check_boundary_violations.py — fail if a PR crosses service boundaries."""
import subprocess, sys, re
from collections import defaultdict

# Map path prefix to owning team
BOUNDARIES = {
    "services/prompt-service/": "prompt",
    "services/tool-gateway/": "tools",
    "services/eval-service/": "eval",
    "services/agent-service/": "agent",
    "shared/": "shared",
    "infra/": "infra",
    ".github/": "platform",
}

# These combinations are always suspicious
FORBIDDEN_COMBOS = {
    frozenset(["prompt", "tools"]),
    frozenset(["prompt", "eval"]),
    frozenset(["tools", "eval"]),
    frozenset(["agent", "eval"]),
}


def get_changed_files(base_branch: str = "main") -> list[str]:
    result = subprocess.run(
        ["git", "diff", "--name-only", f"origin/{base_branch}...HEAD"],
        capture_output=True, text=True, check=True
    )
    return [f.strip() for f in result.stdout.splitlines() if f.strip()]


def classify_files(files: list[str]) -> dict[str, list[str]]:
    by_domain: dict[str, list[str]] = defaultdict(list)
    for f in files:
        matched = False
        for prefix, domain in BOUNDARIES.items():
            if f.startswith(prefix):
                by_domain[domain].append(f)
                matched = True
                break
        if not matched:
            by_domain["root"].append(f)
    return dict(by_domain)


if __name__ == "__main__":
    files = get_changed_files()
    by_domain = classify_files(files)
    touched = set(by_domain.keys()) - {"root", "shared", "infra", "platform"}

    violations = [combo for combo in FORBIDDEN_COMBOS if combo <= touched]

    if violations:
        print(f"BOUNDARY VIOLATION: PR touches {touched} — these domains must not change together.")
        print("Split this PR into separate service PRs, or route changes through shared/ sync.")
        for v in violations:
            print(f"  Conflicting pair: {v}")
        sys.exit(1)

    if "shared" in by_domain and len(touched) > 0:
        print(f"WARNING: PR modifies shared/ AND service code ({touched}).")
        print("Ensure shared/ changes came through the canonical sync workflow, not direct edits.")
        # Warning only, not a hard fail — shared + infra changes can be legitimate

    print(f"OK: PR touches domains {touched or {'root'}} — no boundary violations")

#!/usr/bin/env python3
"""blast_radius.py — identify all services affected by a shared contract change."""
import yaml
from pathlib import Path


def load_catalog(path: str = "service-catalog.yaml") -> list[dict]:
    with open(path) as f:
        return yaml.safe_load(f)["services"]


def find_consumers(catalog: list[dict], shared_path: str) -> list[dict]:
    """Return services that consume the given shared/ path."""
    return [
        svc for svc in catalog
        if any(shared_path in dep for dep in svc.get("consumes", []))
    ]


def find_publisher(catalog: list[dict], shared_path: str) -> dict | None:
    """Return the service that publishes to the given shared/ path."""
    for svc in catalog:
        if any(shared_path in pub for pub in svc.get("publishes", [])):
            return svc
    return None


def blast_radius_report(shared_path: str) -> None:
    catalog = load_catalog()
    publisher = find_publisher(catalog, shared_path)
    consumers = find_consumers(catalog, shared_path)

    print(f"Blast radius for change to: {shared_path}")
    print()

    if publisher:
        print(f"Publisher (approves schema change):")
        print(f"  Service : {publisher['name']}")
        print(f"  Team    : {publisher['team']}")
        print(f"  Tech lead: {publisher['tech_lead']}")
        print()

    print(f"Consumers ({len(consumers)} services must review):")
    for svc in consumers:
        print(f"  - {svc['name']:30s}  team={svc['team']}  oncall={svc['oncall_rotation']}")
    print()

    all_teams = {svc["team"] for svc in consumers}
    if publisher:
        all_teams.add(publisher["team"])

    print(f"Required CODEOWNERS approvals: {', '.join(sorted(all_teams))}")
    print(f"Notify oncall rotations: {', '.join(svc['oncall_rotation'] for svc in consumers)}")


if __name__ == "__main__":
    import sys
    shared_path = sys.argv[1] if len(sys.argv) > 1 else "shared/tool-schemas"
    blast_radius_report(shared_path)
